// Meslek adı çevirisi: o dilde varsa onu, yoksa Türkçe adı döndürür.
export function mc(ad, lng) {
  const k = (lng || "tr").split("-")[0];
  if (k === "tr") return ad;
  return (meslekCevir[ad] && meslekCevir[ad][k]) || ad;
}

